import elasticsearch
from elasticsearch import Elasticsearch

es = Elasticsearch(["localhost:9200"])

# Prevent unauthorized access to the Elasticsearch cluster
es.transport.use_ssl = True
es.transport.verify_certs = False

# Index a document
doc = {
    "title": "My Document",
    "content": "This is my document"
}
es.index(index="my-index", id=1, body=doc)

# Search for documents
query = {
    "query": {
        "match": {
            "title": "document"
        }
    }
}
results = es.search(index="my-index", body=query)
print(results["hits"]["hits"])

# Aggregate logs
logs = [
    {"message": "Log message 1"},
    {"message": "Log message 2"},
    {"message": "Log message 3"}
]
es.bulk(index="my-log-index", body=logs)